# =========================================================
# INTEGRATED BACKEND: DELTA MODBUS TCP CLIENT
# Added into one-file version. This class is optional and does not break the app
# if pyModbusTCP is not installed until you try to connect by TCP.
# =========================================================
class DeltaModbusTCPClient:
    """Simple Delta PLC Modbus TCP helper for D / M / X / Y devices.

    D = Holding Register
    M = Coil
    X = Discrete Input
    Y = Coil

    Note: Some Delta PLC models require Modbus address offset mapping for X/Y/M/D.
    If your PLC map is not direct, adjust address conversion in _device_to_address().
    """

    def __init__(self):
        self.client = None
        self.host = ""
        self.port = 502
        self.unit_id = 1
        self.connected = False
        self.last_error = ""

    def connect(self, host, port=502, unit_id=1, timeout=2):
        self.host = str(host).strip()
        self.port = int(port)
        self.unit_id = int(unit_id)
        self.last_error = ""

        try:
            from pyModbusTCP.client import ModbusClient
        except Exception as e:
            self.connected = False
            self.last_error = f"pyModbusTCP not installed: {e}. Install with: pip install pyModbusTCP"
            print(f"❌ Modbus TCP import error: {self.last_error}")
            return False

        try:
            self.client = ModbusClient(
                host=self.host,
                port=self.port,
                unit_id=self.unit_id,
                auto_open=True,
                auto_close=False,
                timeout=timeout,
            )
            self.connected = bool(self.client.open())
            if not self.connected:
                self.last_error = f"Cannot connect to {self.host}:{self.port} unit_id={self.unit_id}"
            return self.connected
        except Exception as e:
            self.connected = False
            self.last_error = str(e)
            print(f"❌ Modbus TCP connect error: {e}")
            return False

    def close(self):
        try:
            if self.client:
                self.client.close()
        except Exception:
            pass
        self.connected = False

    def _check_connection(self):
        return self.client is not None and self.connected

    def _parse_bool(self, value):
        if isinstance(value, bool):
            return value
        if isinstance(value, int):
            return value != 0
        text = str(value).strip().upper()
        if text in ("1", "ON", "TRUE", "HIGH"):
            return True
        if text in ("0", "OFF", "FALSE", "LOW"):
            return False
        raise ValueError("Bit value must be ON/OFF, TRUE/FALSE, HIGH/LOW, or 1/0")

    def _device_to_address(self, device):
        device = str(device).upper().strip().replace(" ", "")
        if len(device) < 2:
            raise ValueError("Invalid PLC device address")
        prefix = device[0]
        address = int(device[1:])
        return prefix, address

    def read_device(self, device):
        if not self._check_connection():
            self.last_error = "Modbus TCP is not connected"
            return None

        try:
            prefix, addr = self._device_to_address(device)

            if prefix == "D":
                value = self.client.read_holding_registers(addr, 1)
                return value[0] if value else None

            if prefix == "M":
                value = self.client.read_coils(addr, 1)
                return bool(value[0]) if value else None

            if prefix == "X":
                value = self.client.read_discrete_inputs(addr, 1)
                return bool(value[0]) if value else None

            if prefix == "Y":
                value = self.client.read_coils(addr, 1)
                return bool(value[0]) if value else None

            self.last_error = f"Unsupported device prefix: {prefix}"
            return None
        except Exception as e:
            self.last_error = str(e)
            print(f"❌ Modbus TCP read error {device}: {e}")
            return None

    def write_device(self, device, value):
        if not self._check_connection():
            self.last_error = "Modbus TCP is not connected"
            return False

        try:
            prefix, addr = self._device_to_address(device)

            if prefix == "D":
                ivalue = int(value)
                if ivalue < 0 or ivalue > 65535:
                    raise ValueError("D register value must be 0 - 65535")
                return bool(self.client.write_single_register(addr, ivalue))

            if prefix in ("M", "Y"):
                state = self._parse_bool(value)
                return bool(self.client.write_single_coil(addr, state))

            if prefix == "X":
                self.last_error = "X input is read-only and cannot be written"
                return False

            self.last_error = f"Unsupported device prefix: {prefix}"
            return False
        except Exception as e:
            self.last_error = str(e)
            print(f"❌ Modbus TCP write error {device}: {e}")
            return False


# =========================================================
# INTEGRATED BACKEND: MES / TDC MANAGER
# Put DLLFunctionAll.dll and TDC_DLL.dll inside: <same folder as code.py>/mes/dll/
# This keeps MES/TDC separated from UI logic while still staying in one file.
# =========================================================
MES_INSTANCE = None
MES_LAST_STATUS = "NOT_INITIALIZED"
MES_LAST_ERROR = ""


def initialize_mes(enable=True, force_reinit=False):
    global MES_INSTANCE, MES_LAST_STATUS, MES_LAST_ERROR

    MES_LAST_ERROR = ""

    if not enable:
        MES_LAST_STATUS = "DISABLED"
        MES_INSTANCE = None
        return None

    if MES_INSTANCE is not None and not force_reinit:
        MES_LAST_STATUS = "ALREADY_ONLINE"
        return MES_INSTANCE

    try:
        from pathlib import Path
        import importlib
    except Exception as e:
        MES_LAST_STATUS = "IMPORT_ERROR"
        MES_LAST_ERROR = str(e)
        return None

    base_dir = Path(__file__).resolve().parent
    dll_dir = base_dir / "mes" / "dll"
    dll_full_path = dll_dir / "DLLFunctionAll.dll"
    tdc_path = dll_dir / "TDC_DLL.dll"

    if not dll_dir.exists():
        MES_LAST_STATUS = "DLL_FOLDER_NOT_FOUND"
        MES_LAST_ERROR = f"DLL folder not found: {dll_dir}"
        print(f"❌ {MES_LAST_ERROR}")
        return None

    if not tdc_path.exists():
        MES_LAST_STATUS = "TDC_DLL_NOT_FOUND"
        MES_LAST_ERROR = f"TDC_DLL.dll not found: {tdc_path}"
        print(f"❌ {MES_LAST_ERROR}")
        return None

    if not dll_full_path.exists():
        MES_LAST_STATUS = "DLL_NOT_FOUND"
        MES_LAST_ERROR = f"DLLFunctionAll.dll not found: {dll_full_path}"
        print(f"❌ {MES_LAST_ERROR}")
        return None

    if str(dll_dir) not in sys.path:
        sys.path.append(str(dll_dir))

    old_cwd = os.getcwd()
    try:
        os.chdir(str(dll_dir))

        try:
            ctypes.WinDLL(str(tdc_path))
            print("✅ Step 1: TDC_DLL.dll loaded")
        except Exception as e:
            MES_LAST_STATUS = "TDC_LOAD_ERROR"
            MES_LAST_ERROR = str(e)
            print(f"❌ Step 1 Error: {e}")
            return None

        try:
            import clr
        except Exception as e:
            MES_LAST_STATUS = "PYTHONNET_NOT_FOUND"
            MES_LAST_ERROR = f"Cannot import clr/pythonnet: {e}"
            print(f"❌ {MES_LAST_ERROR}")
            return None

        try:
            clr.AddReference(str(dll_full_path))
            print("✅ Step 2: AddReference successful")
        except Exception as e:
            MES_LAST_STATUS = "ADD_REFERENCE_ERROR"
            MES_LAST_ERROR = str(e)
            print(f"❌ AddReference Error: {e}")
            return None

        try:
            dll_module = importlib.import_module("DLLFunctionAll")
            Main_fn = getattr(dll_module, "Main_fn")
        except Exception as e:
            MES_LAST_STATUS = "IMPORT_DLL_MODULE_ERROR"
            MES_LAST_ERROR = str(e)
            print(f"❌ DLL module import error: {e}")
            return None

        try:
            MES_INSTANCE = Main_fn()
            MES_LAST_STATUS = "ONLINE"
            print("✅ Step 3: Main_fn instance created successfully")
        except Exception as e:
            MES_LAST_STATUS = "INSTANCE_CREATE_ERROR"
            MES_LAST_ERROR = str(e)
            print(f"❌ Main_fn create error: {e}")
            return None

        try:
            print(f"📄 Result from textre: {MES_INSTANCE.textre()}")
        except Exception as e:
            print(f"⚠ MES textre() test failed: {e}")

        return MES_INSTANCE

    except Exception as e:
        MES_LAST_STATUS = "ERROR"
        MES_LAST_ERROR = str(e)
        print(f"❌ MES initialization error: {e}")
        return None
    finally:
        try:
            os.chdir(old_cwd)
        except Exception:
            pass


def get_mes():
    return MES_INSTANCE


def get_mes_status():
    return {
        "status": MES_LAST_STATUS,
        "error": MES_LAST_ERROR,
        "online": MES_INSTANCE is not None,
    }


def reset_mes():
    global MES_INSTANCE, MES_LAST_STATUS, MES_LAST_ERROR
    MES_INSTANCE = None
    MES_LAST_STATUS = "NOT_INITIALIZED"
    MES_LAST_ERROR = ""

