def pixmap_from_base64(b64_text):
    try:
        clean_text = "".join(str(b64_text).split())
        if clean_text.startswith("data:image") and "," in clean_text:
            clean_text = clean_text.split(",", 1)[1]
        data = base64.b64decode(clean_text)
        pixmap = QPixmap()
        pixmap.loadFromData(data)
        return pixmap
    except Exception:
        return QPixmap()


def pixmap_from_base64_or_file(b64_text, file_path):
    pixmap = pixmap_from_base64(b64_text)
    if not pixmap.isNull():
        return pixmap
    if file_path and os.path.exists(file_path):
        return QPixmap(file_path)
    return QPixmap()


def icon_from_base64_or_file(b64_text, file_path):
    pixmap = pixmap_from_base64_or_file(b64_text, file_path)
    if pixmap.isNull():
        return QIcon()
    return QIcon(pixmap)


def normalize_roi_data(roi, default_type="rect"):
    """Return ROI as dict: {type, x, y, w, h}. Compatible with old tuple/list projects."""
    if isinstance(roi, dict):
        rtype = str(roi.get("type", default_type)).lower()
        if rtype not in ("rect", "circle"):
            rtype = "rect"
        x = int(roi.get("x", 0))
        y = int(roi.get("y", 0))
        w = int(roi.get("w", roi.get("r", 10) * 2))
        h = int(roi.get("h", roi.get("r", 10) * 2))
        out = {"type": rtype, "x": x, "y": y, "w": w, "h": h}
        if isinstance(roi.get("settings"), dict):
            out["settings"] = roi.get("settings", {})
        return out
    if isinstance(roi, (list, tuple)) and len(roi) >= 4:
        return {"type": default_type, "x": int(roi[0]), "y": int(roi[1]), "w": int(roi[2]), "h": int(roi[3])}
    return {"type": default_type, "x": 0, "y": 0, "w": 10, "h": 10}


def roi_bbox(roi):
    r = normalize_roi_data(roi)
    return r["x"], r["y"], r["w"], r["h"]


def roi_to_project(roi):
    r = normalize_roi_data(roi)
    out = {"type": r["type"], "x": int(r["x"]), "y": int(r["y"]), "w": int(r["w"]), "h": int(r["h"])}
    if isinstance(r.get("settings"), dict):
        out["settings"] = r.get("settings", {})
    return out


class ModernDialog(QDialog):
    def __init__(self, title: str, parent=None, width: int = 420, height: int = 280):
        super().__init__(parent)
        self.setWindowFlags(Qt.FramelessWindowHint | Qt.Dialog)
        self.setModal(True)
        self.resize(width, height)
        self.drag_pos = None
        self.setStyleSheet(f"background:{PANEL_BG}; border:1px solid {BORDER};")

        root = QVBoxLayout(self)
        root.setContentsMargins(0, 0, 0, 0)
        root.setSpacing(0)

        self.topbar = QFrame()
        self.topbar.setFixedHeight(38)
        self.topbar.setStyleSheet(f"background:{RESULT_BG}; border-bottom:1px solid {BORDER};")
        topbar_layout = QHBoxLayout(self.topbar)
        topbar_layout.setContentsMargins(12, 0, 8, 0)

        self.title_label = QLabel(title)
        self.title_label.setStyleSheet(f"color:{TEXT}; font:600 10pt 'Segoe UI';")
        topbar_layout.addWidget(self.title_label)
        topbar_layout.addStretch()

        close_btn = QPushButton("✕")
        close_btn.setFixedSize(28, 28)
        close_btn.setStyleSheet(
            f"QPushButton{{background:transparent;color:{TEXT};border:none;font:700 10pt 'Segoe UI';}}"
            f"QPushButton:hover{{background:#1e293b;}}"
        )
        close_btn.clicked.connect(self.reject)
        topbar_layout.addWidget(close_btn)
        root.addWidget(self.topbar)

        self.body = QWidget()
        self.body_layout = QVBoxLayout(self.body)
        self.body_layout.setContentsMargins(20, 20, 20, 20)
        self.body_layout.setSpacing(12)
        root.addWidget(self.body)

    def mousePressEvent(self, event):
        if event.button() == Qt.LeftButton and event.pos().y() <= self.topbar.height():
            self.drag_pos = event.globalPos() - self.frameGeometry().topLeft()
            event.accept()

    def mouseMoveEvent(self, event):
        if self.drag_pos and event.buttons() & Qt.LeftButton:
            self.move(event.globalPos() - self.drag_pos)
            event.accept()

    def mouseReleaseEvent(self, event):
        self.drag_pos = None
        event.accept()

    def line_edit(self, placeholder: str, password: bool = False):
        w = QLineEdit()
        w.setPlaceholderText(placeholder)
        if password:
            # Production security: never show password characters while typing.
            w.setEchoMode(QLineEdit.Password)
            try:
                w.setInputMethodHints(Qt.ImhHiddenText | Qt.ImhNoPredictiveText | Qt.ImhNoAutoUppercase)
            except Exception:
                pass
            try:
                w.setContextMenuPolicy(Qt.NoContextMenu)
            except Exception:
                pass
        w.setStyleSheet(
            f"QLineEdit{{background:{INPUT_BG}; color:{TEXT}; border:1px solid {BORDER}; border-radius:10px; padding:10px; font:10pt 'Segoe UI';}}"
            f"QLineEdit:focus{{border:1px solid {ACCENT};}}"
        )
        return w

    def button_row(self, primary_text: str, primary_callback, secondary_text: str = "Cancel"):
        row = QHBoxLayout()
        row.addStretch()

        cancel = QPushButton(secondary_text)
        cancel.setFixedSize(120, 40)
        cancel.setStyleSheet(
            f"QPushButton{{background:#334155;color:{TEXT};border:none;border-radius:12px;font:600 10pt 'Segoe UI';}}"
            f"QPushButton:hover{{background:#475569;}}"
        )
        cancel.clicked.connect(self.reject)
        row.addWidget(cancel)

        ok = QPushButton(primary_text)
        ok.setFixedSize(120, 40)
        ok.setStyleSheet(
            f"QPushButton{{background:{ACCENT};color:white;border:none;border-radius:12px;font:600 10pt 'Segoe UI';}}"
            f"QPushButton:hover{{background:#2563eb;}}"
        )
        ok.clicked.connect(primary_callback)
        row.addWidget(ok)
        return row


class AuthManager:
    """Load all admin/user permission from auth.json only.

    If auth.json is missing or invalid, every protected action is denied.
    Put auth.json in either:
      1) BASE_DIR/auth.json, or
      2) the same folder as this .py file, or
      3) the current working directory.
    """
    def __init__(self, primary_path=AUTH_CONFIG_PATH):
        self.primary_path = primary_path
        self.config_path = None
        self.config = {}
        self.admins = []
        self.users = []
        self.load()

    def candidate_paths(self):
        paths = [self.primary_path]
        try:
            script_dir = os.path.dirname(os.path.abspath(__file__))
            paths.append(os.path.join(script_dir, "auth.json"))
        except Exception:
            pass
        paths.append(os.path.join(os.getcwd(), "auth.json"))
        unique = []
        for p in paths:
            if p and p not in unique:
                unique.append(p)
        return unique

    def load(self):
        self.config = {}
        self.admins = []
        self.users = []
        self.config_path = None
        for path in self.candidate_paths():
            if os.path.exists(path):
                try:
                    with open(path, "r", encoding="utf-8") as f:
                        self.config = json.load(f)
                    self.config_path = path
                    security = self.config.get("security", {})
                    self.admins = list(security.get("admins", []))
                    self.users = list(security.get("users", []))
                    return True
                except Exception:
                    self.config = {}
                    self.admins = []
                    self.users = []
                    self.config_path = None
                    return False
        return False

    def is_ready(self):
        return bool(self.config_path and self.config)

    def authenticate_admin(self, username, password):
        # No hardcoded admin allowed. Everything must come from auth.json.
        username = str(username).strip()
        password = str(password).strip()
        for admin in self.admins:
            if not admin.get("active", True):
                continue
            if str(admin.get("username", "")).strip() == username and str(admin.get("password", "")).strip() == password:
                data = dict(admin)
                data["auth_type"] = "admin"
                data["display_name"] = data.get("username", username)
                data["id"] = "ADMIN"
                return data
        return None

    def authenticate_engineer(self, username, password):
        """Engineer mode rule:
        1) Admin can login with security.admins[].username/password.
        2) Any active user in security.users[] can login with name/id.
        3) Anyone not in auth.json stays Operator Mode only.
        """
        username = str(username).strip()
        password = str(password).strip()

        admin = self.authenticate_admin(username, password)
        if admin:
            return admin

        ok, user = self.is_authorized_user(username, password)
        if ok and user:
            data = dict(user)
            data["auth_type"] = "auth_user"
            data["username"] = data.get("name", username)
            data["display_name"] = data.get("name", username)
            # All active auth.json users are allowed to enter Engineer Mode by request.
            data["engineer_mode"] = True
            return data

        return None

    def find_user_by_id(self, emp_id):
        emp_id = str(emp_id).strip()
        for user in self.users:
            if not user.get("active", True):
                continue
            if str(user.get("id", "")).strip() == emp_id:
                return dict(user)
        return None

    def is_authorized_user(self, name, emp_id):
        user = self.find_user_by_id(emp_id)
        if not user:
            return False, None
        # Name check is case-insensitive but ID is the primary key.
        if name and str(user.get("name", "")).strip().lower() != str(name).strip().lower():
            return False, user
        return True, user

    def user_can(self, user, action):
        if not user:
            return False
        # Requested rule: every active user listed in auth.json can enter Engineer Mode
        # and access setup / ROI / tune / project tools. Unknown users remain Operator only.
        if action in {"load_project", "save_project", "copy_project", "new_project", "setup", "roi", "tune"}:
            return True
        role = str(user.get("role", "operator")).lower()
        permissions = self.config.get("permissions", {})
        allowed_roles = permissions.get(action, [])
        if not allowed_roles:
            return True
        return role in [str(r).lower() for r in allowed_roles]

    def describe_source(self):
        return self.config_path or "auth.json not found"


