        self.operator_card_fail = self._operator_metric_label("FAIL", "0", "#ef4444")
        self.operator_card_yield = self._operator_metric_label("YIELD", "0.00%", "#facc15")
        self.operator_card_consecutive_ng = self._operator_metric_label("NG", "0", "#f97316")
        self.operator_card_shift = self._operator_metric_label("SHIFT", "00:00:00", "#a78bfa")
        self.operator_card_camera = self._operator_metric_label("CAM", "OFFLINE", "#ef4444")
