def _plc_adv_decode_error(err):
    s = str(err or "").lower()
    if "timeout" in s or "timed out" in s or "no response" in s:
        return "TIMEOUT: PLC ไม่ตอบกลับ / ตรวจสาย LAN-RS485, IP, COM, Baud, Slave/Unit ID"
    if "illegal" in s and "address" in s:
        return "ILLEGAL ADDRESS: Address ไม่ถูกต้องหรือ PLC รุ่นนี้ไม่รองรับ"
    if "crc" in s:
        return "CRC ERROR: สัญญาณรบกวน/สาย RS485/กราวด์/baud/parity อาจไม่ตรง"
    if "connection" in s or "connect" in s or "refused" in s:
        return "CONNECT ERROR: เชื่อมต่อไม่ได้ ตรวจ IP/Port/Firewall/PLC Ethernet setting"
    if "write" in s:
        return "WRITE ERROR: เขียนค่าไม่สำเร็จ ตรวจสิทธิ์, device type, และโหมด PLC"
    if not str(err or "").strip():
        return ""
    return str(err)


def _plc_adv_is_true_value(value):
    return str(value).strip().upper() in ("1", "ON", "TRUE", "HIGH")


def _plc_adv_is_false_value(value):
    return str(value).strip().upper() in ("0", "OFF", "FALSE", "LOW")


def _plc_adv_device_prefix(dev):
    d = str(dev or "").strip().upper()
    return d[0] if d else ""


def _plc_adv_safe_filename(name):
    return "".join(c if c.isalnum() or c in "-_" else "_" for c in str(name))[:80]


_PLC_ORIG_BUILD_UI = PLCDebugPage._build_ui
_PLC_ORIG_SET_STATUS = PLCDebugPage._set_status
_PLC_ORIG_UPDATE_DIAG = PLCDebugPage.update_diagnostics_panel
_PLC_ORIG_MODBUS_CALL = PLCDebugPage._modbus_call
_PLC_ORIG_MONITOR = PLCDebugPage.monitor_devices
