_PLC_ORIG_CELL_CHANGED = PLCDebugPage.handle_device_table_cell_changed
_PLC_ORIG_SAVE_IO = PLCDebugPage.save_io_changes
_PLC_ORIG_CONSOLE_LINE = PLCDebugPage.add_plc_console_line
_PLC_ORIG_FORCE_DEVICE = PLCDebugPage.force_device


