def _plc_adv_set_status(self, state, detail=""):
    _PLC_ORIG_SET_STATUS(self, state, detail)
    try:
        self._plc_adv_update_alarm_banner(detail)
    except Exception:
        pass


def _plc_adv_update_alarm_banner(self, detail=""):
    if not hasattr(self, "plc_alarm_banner"):
        return
    force = bool(getattr(self, "force_active", False) or getattr(self, "forced_devices", set()))
    if force:
        text = "🟡 FORCE ACTIVE - เปิด Force Output อยู่"
        css = "QLabel{background:#713f12;color:#fff7ed;border:2px solid #f59e0b;border-radius:11px;padding:7px;font:900 11pt 'Segoe UI';}"
    elif getattr(self, "connected", False):
        text = "🟢 PLC ONLINE - สื่อสารกับ PLC ได้"
        css = "QLabel{background:#14532d;color:#dcfce7;border:2px solid #22c55e;border-radius:11px;padding:7px;font:900 11pt 'Segoe UI';}"
    elif getattr(self, "client", None):
        text = "🟠 PORT OPEN ONLY - ยังไม่มี PLC Reply"
        css = "QLabel{background:#713f12;color:#fff7ed;border:2px solid #f59e0b;border-radius:11px;padding:7px;font:900 11pt 'Segoe UI';}"
    else:
        text = "🔴 PLC OFFLINE - ยังไม่ได้เชื่อมต่อ"
        css = "QLabel{background:#450a0a;color:#fecaca;border:2px solid #ef4444;border-radius:11px;padding:7px;font:900 11pt 'Segoe UI';}"
    if detail:
        text += f" | {str(detail)[:90]}"
    self.plc_alarm_banner.setText(text)
    self.plc_alarm_banner.setStyleSheet(css)


def _plc_adv_modbus_call(self, fn, *args, **kwargs):
    res, err = _PLC_ORIG_MODBUS_CALL(self, fn, *args, **kwargs)
    try:
        if getattr(self, "last_response_ms", None) is not None:
            hist = getattr(self, "response_history_ms", [])
            hist.append(int(self.last_response_ms))
            self.response_history_ms = hist[-300:]
        if err and hasattr(self, "add_plc_console_line"):
            self.add_plc_console_line(_plc_adv_decode_error(err), "FAIL")
        self._plc_adv_update_dashboard()
    except Exception:
        pass
    return res, err


def _plc_adv_update_diagnostics_panel(self):
    _PLC_ORIG_UPDATE_DIAG(self)
    try:
        self._plc_adv_update_dashboard()
        self._plc_adv_update_alarm_banner()
    except Exception:
        pass


def _plc_adv_update_dashboard(self):
    if not hasattr(self, "dash_devices_card"):
        return
    total = int(getattr(self, "tx_count", 0) or 0)
    errors = int(getattr(self, "error_count", 0) or 0) + int(getattr(self, "timeout_count", 0) or 0)
    ok = max(total - errors, 0)
    success = f"{(ok / total * 100):.1f}%" if total else "-"
    hist = getattr(self, "response_history_ms", [])
    avgmax = f"{sum(hist)//len(hist)} / {max(hist)} ms" if hist else "-"
    changed = len(getattr(self, "pending_table_changes", {}) or {})
    forced = len(getattr(self, "forced_devices", set()) or set())
    dev_count = self.device_table.rowCount() if hasattr(self, "device_table") else 0
    self._set_card_value(self.dash_devices_card, "DEVICE COUNT", str(dev_count), TEXT)
    self._set_card_value(self.dash_changed_card, "CHANGED", str(changed), "#f59e0b" if changed else TEXT)
    self._set_card_value(self.dash_force_card, "FORCE COUNT", str(forced), "#f59e0b" if forced else TEXT)
    self._set_card_value(self.dash_success_card, "SUCCESS RATE", success, "#22c55e" if total and errors == 0 else ("#f59e0b" if total else TEXT))
    self._set_card_value(self.dash_avg_card, "AVG / MAX", avgmax, TEXT)
    online = "ONLINE" if getattr(self, "connected", False) else "OFFLINE"
    self._set_card_value(self.dash_online_card, "ONLINE TIME", online, "#22c55e" if online == "ONLINE" else "#ef4444")


def _plc_adv_monitor_devices(self):
    if getattr(self, "monitor_paused", False):
        try:
            self._set_status("online" if self.connected else "offline", "Monitor paused / หยุดภาพข้อมูลชั่วคราว")
        except Exception:
            pass
        return
    try:
        self._plc_adv_check_force_timeout()
    except Exception:
        pass
    return _PLC_ORIG_MONITOR(self)


def _plc_adv_toggle_pause(self):
    self.monitor_paused = not getattr(self, "monitor_paused", False)
    if self.monitor_paused:
        self.btn_pause_monitor_adv.setText("▶ Resume Monitor")
        self.add_plc_console_line("MONITOR PAUSED / หยุด Monitor ชั่วคราว", "PENDING")
    else:
        self.btn_pause_monitor_adv.setText("⏸ Pause Monitor")
        self.add_plc_console_line("MONITOR RESUMED / กลับมา Monitor ต่อ", "OK")


def _plc_adv_force_device(self, device, state):
    res = _PLC_ORIG_FORCE_DEVICE(self, device, state)
    try:
        if state:
            self._plc_adv_arm_force_timeout()
        self._plc_adv_update_alarm_banner()
        self._plc_adv_update_dashboard()
    except Exception:
        pass
    return res


def _plc_adv_arm_force_timeout(self):
    txt = self.force_timeout_combo.currentText() if hasattr(self, "force_timeout_combo") else "Manual"
    mins = 0
    if "1 min" in txt:
        mins = 1
    elif "5 min" in txt:
        mins = 5
    elif "10 min" in txt:
        mins = 10
    if mins and (getattr(self, "force_active", False) or getattr(self, "forced_devices", set())):
        self.force_timeout_deadline = time.time() + mins * 60
        self.add_plc_console_line(f"FORCE TIMEOUT ARMED: {mins} min", "PENDING")
    elif not mins:
        self.force_timeout_deadline = None


def _plc_adv_check_force_timeout(self):
    deadline = getattr(self, "force_timeout_deadline", None)
    if not deadline or time.time() < deadline:
        return
    self.force_timeout_deadline = None
    try:
        self.force_enable.setChecked(False)
    except Exception:
        pass
    self.force_authenticated = False
    self.force_active = False
    try:
        self.forced_devices.clear()
    except Exception:
        pass
    self.update_force_safety_ui()
    self._plc_adv_update_alarm_banner("Force timeout auto release")
    self.add_plc_console_line("FORCE TIMEOUT AUTO RELEASED / ปิด Force อัตโนมัติ", "FAIL")
    QMessageBox.warning(self, "Force Timeout", "Force Output ถูกปิดอัตโนมัติเนื่องจากหมดเวลา")


def _plc_adv_is_protected_device(self, dev):
    dev = str(dev or "").upper().strip()
    raw = self.protected_input.text() if hasattr(self, "protected_input") else ""
    parts = [p.strip().upper() for p in raw.split(",") if p.strip()]
    for p in parts:
        if p == "X" and dev.startswith("X"):
            return True
        if "-" in p and len(p) >= 3:
            try:
                a, b = p.split("-", 1)
                pa, na = a[0], int("".join(ch for ch in a[1:] if ch.isdigit()))
                pb, nb = b[0], int("".join(ch for ch in b[1:] if ch.isdigit()))
                if dev.startswith(pa) and pa == pb:
                    nd = int("".join(ch for ch in dev[1:] if ch.isdigit()) or "-1")
                    if na <= nd <= nb:
                        return True
            except Exception:
                pass
        elif p and dev.startswith(p):
            return True
    return False


def _plc_adv_handle_cell_changed(self, row, col):
    _PLC_ORIG_CELL_CHANGED(self, row, col)
    try:
        dev_item = self.device_table.item(row, 0)
        if dev_item and self._plc_adv_is_protected_device(dev_item.text()) and col == 1:
            self._set_table_text(row, 3, "PROTECTED - NEED CARE")
            self.add_plc_console_line(f"PROTECTED EDIT MARKED: {dev_item.text()}", "PENDING")
        self._plc_adv_apply_filter()
        self._plc_adv_update_dashboard()
    except Exception:
        pass


def _plc_adv_save_io_changes(self):
    try:
        changes = dict(getattr(self, "pending_table_changes", {}) or {})
        protected = [ch.get("device", "") for ch in changes.values() if self._plc_adv_is_protected_device(ch.get("device", ""))]
        y_outputs = [ch.get("device", "") for ch in changes.values() if str(ch.get("device", "")).upper().startswith("Y")]
        if protected or y_outputs:
            msg = "Critical PLC write detected.\n\n"
            if protected:
                msg += "Protected: " + ", ".join(protected[:20]) + "\n"
            if y_outputs:
                msg += "Y Output: " + ", ".join(y_outputs[:20]) + "\n"
            msg += "\nยืนยันอีกครั้งว่าเครื่องอยู่ในสภาวะปลอดภัยก่อนเขียนค่า"
            ans = QMessageBox.question(self, "Dual Confirmation", msg, QMessageBox.Yes | QMessageBox.No, QMessageBox.No)
            if ans != QMessageBox.Yes:
                self.add_plc_console_line("CRITICAL WRITE CANCELLED", "FAIL")
                return
    except Exception:
        pass
    res = _PLC_ORIG_SAVE_IO(self)
    try:
        self._plc_adv_apply_filter()
        self._plc_adv_update_dashboard()
        self._plc_adv_update_alarm_banner()
    except Exception:
        pass
    return res


def _plc_adv_set_device_value_with_highlight(self, row, dev, typ, value):
    _PLC_ORIG_SET_VALUE(self, row, dev, typ, value)
    try:
        dev = str(dev).upper().strip()
        val = str(value).strip().upper()
        # keep trend history for every device
        hist = self.device_value_history.get(dev, [])
        try:
            y = float(val) if val not in ("ON", "OFF", "TRUE", "FALSE") else (1.0 if _plc_adv_is_true_value(val) else 0.0)
        except Exception:
            y = None
        hist.append((time.time(), val, y))
        self.device_value_history[dev] = hist[-120:]

        item = self.device_table.item(row, 1)
        if item:
            if val in ("ON", "1", "TRUE", "HIGH"):
                item.setBackground(QColor("#14532d"))
                item.setForeground(QColor("#dcfce7"))
            elif val in ("OFF", "0", "FALSE", "LOW"):
                item.setBackground(QColor("#1f2937"))
                item.setForeground(QColor("#d1d5db"))
            elif val == "ERR":
                item.setBackground(QColor("#7f1d1d"))
                item.setForeground(QColor("#fee2e2"))
            else:
                item.setForeground(QColor("#fef3c7"))
        if dev in getattr(self, "forced_devices", set()):
            status_item = self.device_table.item(row, 3)
            if status_item:
                status_item.setBackground(QColor("#713f12"))
                status_item.setForeground(QColor("#fff7ed"))
        self._plc_adv_update_bit_and_trend()
    except Exception:
        pass


def _plc_adv_apply_filter(self):
    if not hasattr(self, "device_table"):
        return
    q = self.plc_search_input.text().strip().upper() if hasattr(self, "plc_search_input") else ""
    changed_only = self.chk_table_changed_only.isChecked() if hasattr(self, "chk_table_changed_only") else False
    for row in range(self.device_table.rowCount()):
        texts = []
        for col in range(self.device_table.columnCount()):
            it = self.device_table.item(row, col)
            texts.append(it.text().upper() if it else "")
        row_text = " ".join(texts)
        is_alarm = any(k in row_text for k in ("ERR", "FAIL", "PENDING", "PROTECTED", "FORCE"))
        show = True
        if q and q not in row_text:
            show = False
        if changed_only and not is_alarm:
            show = False
        self.device_table.setRowHidden(row, not show)


def _plc_adv_update_bit_and_trend(self):
    if not hasattr(self, "plc_bit_trend_panel") or not hasattr(self, "device_table"):
        return
    row = self.device_table.currentRow()
    if row < 0:
        return
    dev_item = self.device_table.item(row, 0)
    val_item = self.device_table.item(row, 1)
    typ_item = self.device_table.item(row, 2)
    if not dev_item:
        return
    dev = dev_item.text().strip().upper()
    val = val_item.text().strip() if val_item else "-"
    typ = typ_item.text().strip().upper() if typ_item else ""
    lines = [f"DEVICE: {dev}   TYPE: {typ}   VALUE: {val}", ""]
    # Bit view for numeric registers
    try:
        iv = int(float(str(val)))
        bits = format(iv & 0xFFFF, "016b")
        lines.append("BIT VIEW 16-bit:")
        lines.append("bit15                                    bit0")
        lines.append(" ".join([bits[i:i+4] for i in range(0, 16, 4)]))
        on_bits = [str(i) for i in range(16) if iv & (1 << i)]
        lines.append("ON bits: " + (", ".join(on_bits) if on_bits else "none"))
    except Exception:
        if _plc_adv_is_true_value(val):
            lines.append("BIT VALUE: ON / 1")
        elif _plc_adv_is_false_value(val):
            lines.append("BIT VALUE: OFF / 0")
        else:
            lines.append("BIT VIEW: not numeric yet")
    lines.append("")
    # Trend sparkline
    hist = getattr(self, "device_value_history", {}).get(dev, [])
    nums = [h[2] for h in hist if h[2] is not None]
    lines.append("TREND last values:")
    if nums:
        mn, mx = min(nums), max(nums)
        chars = "▁▂▃▄▅▆▇█"
        spark = ""
        for n in nums[-60:]:
            idx = 0 if mx == mn else int((n - mn) / (mx - mn) * (len(chars) - 1))
            spark += chars[max(0, min(len(chars)-1, idx))]
        lines.append(spark)
        lines.append(f"min={mn} max={mx} last={nums[-1]}")
    else:
        lines.append("No trend yet. Start monitor to collect data.")
    lines.append("")
    lines.append(f"Scaling note: {self.scaling_input.text() if hasattr(self, 'scaling_input') else '-'}")
    self.plc_bit_trend_panel.setPlainText("\n".join(lines))


def _plc_adv_add_bookmark(self):
    row = self.device_table.currentRow() if hasattr(self, "device_table") else -1
    if row < 0:
        QMessageBox.information(self, "Favorite", "Select a device row first.")
        return
    dev = self.device_table.item(row, 0).text().strip().upper() if self.device_table.item(row, 0) else ""
    typ = self.device_table.item(row, 2).text().strip().upper() if self.device_table.item(row, 2) else "WORD"
    if not dev:
        return
    item = {"device": dev, "type": typ}
    if item not in self.plc_bookmarks:
        self.plc_bookmarks.append(item)
    self.add_plc_console_line(f"FAVORITE ADDED: {dev} ({typ})", "OK")


def _plc_adv_load_bookmarks(self):
    if not getattr(self, "plc_bookmarks", []):
        QMessageBox.information(self, "Favorites", "No favorites yet. Select a row and press Add Favorite.")
        return
    self.clear_device_table()
    for it in self.plc_bookmarks:
        self._add_device_row(it.get("device", ""), it.get("type", "WORD"))
    self.add_plc_console_line(f"FAVORITES LOADED: {len(self.plc_bookmarks)} devices", "OK")


def _plc_adv_export_audit(self):
    default = os.path.join(BASE_DIR, f"plc_audit_{datetime.now().strftime('%Y%m%d_%H%M%S')}.csv")
    path, _ = QFileDialog.getSaveFileName(self, "Export PLC Audit CSV", default, "CSV Files (*.csv)")
    if not path:
        return
    rows = getattr(self, "plc_write_history", []) or []
    headers = ["time", "user", "device", "type", "before_table", "before_read", "written", "verify_read", "result", "error"]
    try:
        with open(path, "w", newline="", encoding="utf-8-sig") as f:
            writer = csv.DictWriter(f, fieldnames=headers)
            writer.writeheader()
            for r in rows:
                writer.writerow({h: r.get(h, "") for h in headers})
        QMessageBox.information(self, "Export Audit", f"Audit exported:\n{path}")
    except Exception as e:
        QMessageBox.warning(self, "Export Audit", f"Cannot export audit.\n{e}")


def _plc_adv_console_line(self, text, status="INFO"):
    try:
        if status in ("FAIL", "ERROR", "NO READ"):
            text = _plc_adv_decode_error(text)
    except Exception:
        pass
    return _PLC_ORIG_CONSOLE_LINE(self, text, status)


