def main():
    app = QApplication(sys.argv)
    app.setStyle("Fusion")

    # Global dialog style fix for PyQt5/Fusion dark theme.
    # Fixes QMessageBox text becoming black/invisible on dark background.
    app.setStyleSheet("""
        QMessageBox {
            background-color: #1f2937;
            color: #f5f5f5;
            font-family: Segoe UI;
            font-size: 10pt;
        }
        QMessageBox QLabel {
            color: #f5f5f5;
            background-color: transparent;
        }
        QMessageBox QPushButton {
            background-color: #2563eb;
            color: #ffffff;
            border: 1px solid #60a5fa;
            border-radius: 4px;
            padding: 6px 18px;
            min-width: 70px;
        }
        QMessageBox QPushButton:hover {
            background-color: #1d4ed8;
        }
        QDialog {
            background-color: #1f2937;
            color: #f5f5f5;
        }
        QDialog QLabel {
            color: #f5f5f5;
            background-color: transparent;
        }
        QToolTip {
            background-color: #111827;
            color: #ffffff;
            border: 1px solid #3b82f6;
            padding: 6px;
            font-size: 10pt;
        }
    """)
    app_icon = icon_from_base64_or_file(APP_ICON_BASE64, APP_ICON_PATH)
    if not app_icon.isNull():
        app.setWindowIcon(app_icon)
    win = MainWindow()
    if not app_icon.isNull():
        win.setWindowIcon(app_icon)
    win.show()
    sys.exit(app.exec_())


if __name__ == "__main__":
    main()
